output.sparql:
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX bd: <http://www.bigdata.com/rdf#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?director ?directorLabel WHERE {
  ?film wdt:P921 wd:Q193541 ; wdt:P571 ?filmDate ; wdt:P57 ?director .
  FILTER(YEAR(?filmDate) >= 1960 && YEAR(?filmDate) <= 1969)
  ?director wdt:P31 wd:Q5 .
  FILTER NOT EXISTS {
    wd:Q20724369 wdt:P527 ?annualList ; wdt:P527 ?topFilm .
    ?topFilm wdt:P571 ?topFilmDate .
    FILTER(YEAR(?topFilmDate) >= 1960 && YEAR(?topFilmDate) <= 1969)
    FILTER(?film = ?topFilm)
  }
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en" .
  }
}

